changeSet.sql:
-- Fill blocks: a cart slot can fill by unit COUNT, by TIME (seconds), or TO_END of the
-- show instance (music only). COUNT/TIME expand into concrete slots when a clock is
-- applied; TO_END is resolved at push time and needs to survive on the schedule item.
ALTER TABLE clock_template_slot ADD COLUMN IF NOT EXISTS fill_mode VARCHAR(10);
ALTER TABLE clock_template_slot ADD COLUMN IF NOT EXISTS fill_target_seconds INTEGER;
ALTER TABLE clock_template_slot ADD COLUMN IF NOT EXISTS fill_target_count INTEGER;

ALTER TABLE schedule_item ADD COLUMN IF NOT EXISTS fill_mode VARCHAR(10);
ALTER TABLE schedule_item ADD COLUMN IF NOT EXISTS fill_target_seconds INTEGER;
ALTER TABLE schedule_item ADD COLUMN IF NOT EXISTS fill_target_count INTEGER;
